#include<bits/stdc++.h>
using namespace std;
const double eps = 1e-7;
const int K = (1<<18)+5 ;
int T,n,m,line[20][20],fir[K],dp[K];
double x[20],y[20];
int main(){
    cin>>T;
    for(int i=0;i<(1<<18);i++){//初始化，枚举状态
        fir[i]=1;//先假设第一个为0的是第1位
        for(int j=1;i&(1<<(j-1));j++)fir[i]=j+1;
        //如果第j位不为0，那就假设第j+1位是第一个为0的
    }
    while(T--){
        memset(line,0,sizeof(line));//清空数组
        memset(dp,0x3f,sizeof(dp));//初始化数组为极大值
        cin>>n>>m;
        for(int i=1;i<=n;i++)cin>>x[i]>>y[i];//输入每只猪的坐标
        for(int i=1;i<=n;i++){
            for(int j=1;j<=n;j++){//开始预处理抛物线
                if(i==j)continue;//需要两只不同的猪
                if(abs(x[i]*x[i]*x[j]-x[j]*x[j]*x[i])<eps)continue;//除数为0
                if(abs(x[i])<eps)continue;//除数为0
                double a=(y[i]*x[j]-y[j]*x[i])/(x[i]*x[i]*x[j]-x[j]*x[j]*x[i]);//根据方程解出a
                double b=(y[i]-x[i]*x[i]*a)/x[i];//根据方程解出b
                if(a>-eps)continue;//必须满足a<0
                for(int k=1;k<=n;k++)
                    if(abs(a*x[k]*x[k]+b*x[k]-y[k])<eps)line[i][j]|=(1<<(k-1));
                //看看有哪些点在这条抛物线上，统统算进来
            }
        }
        dp[0]=0;//初始化
        //重要环节来了！开始DP！
        for(int s=0;s<(1<<n);s++){//枚举当前猪的生死状态
            int i=fir[s];//取出这次要打的一只猪
            dp[s|(1<<(i-1))]=min(dp[s|(1<<(i-1))],dp[s]+1);//只打这一只猪的转移
            for(int j=1;j<=n;j++)//枚举和i一起被打的猪
                if(i!=j)dp[s|line[i][j]]=min(dp[s|line[i][j]],dp[s]+1);
            //打i和j这两只猪的转移
            //注意这条打i和j的抛物线有可能还顺带打了其他猪
        }
        cout<<dp[(1<<n)-1]<<"\n";//输出最终的答案
    }
    return 0;
}
